namespace sv_cc43e56cc13a41819499ee7600f20493.Client.Services;

public interface IShipmentService
{
    Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

public sealed class ShipmentDetails
{
    public required string TrackingNumber { get; init; }
    public required string Status { get; init; }
    public required string Location { get; init; }
    public required DateTimeOffset EstimatedDelivery { get; init; }
    public required IReadOnlyList<StatusUpdate> StatusUpdates { get; init; }
}

public sealed class StatusUpdate
{
    public required DateTimeOffset Timestamp { get; init; }
    public required string Description { get; init; }
    public required string Location { get; init; }
}

using sv_cc43e56cc13a41819499ee7600f20493.Client.Services;

namespace sv_cc43e56cc13a41819499ee7600f20493.Services;

public sealed class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, ShipmentDetails> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["PKG-001"] = new ShipmentDetails
        {
            TrackingNumber = "PKG-001",
            Status = "In Transit",
            Location = "Chicago, IL",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 25, 17, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 20, 8, 0, 0, TimeSpan.Zero), Description = "Package picked up", Location = "New York, NY" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 21, 14, 30, 0, TimeSpan.Zero), Description = "Arrived at sorting facility", Location = "Philadelphia, PA" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 22, 9, 15, 0, TimeSpan.Zero), Description = "In transit to destination", Location = "Chicago, IL" },
            ]
        },
        ["PKG-002"] = new ShipmentDetails
        {
            TrackingNumber = "PKG-002",
            Status = "Delivered",
            Location = "San Francisco, CA",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 21, 12, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 18, 10, 0, 0, TimeSpan.Zero), Description = "Package picked up", Location = "Seattle, WA" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 19, 16, 0, 0, TimeSpan.Zero), Description = "Arrived at regional hub", Location = "Portland, OR" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 20, 22, 0, 0, TimeSpan.Zero), Description = "Out for delivery", Location = "San Francisco, CA" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 21, 11, 45, 0, TimeSpan.Zero), Description = "Delivered", Location = "San Francisco, CA" },
            ]
        },
        ["PKG-003"] = new ShipmentDetails
        {
            TrackingNumber = "PKG-003",
            Status = "Processing",
            Location = "Dallas, TX",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 28, 15, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 22, 7, 0, 0, TimeSpan.Zero), Description = "Label created", Location = "Dallas, TX" },
            ]
        },
    };

    public async Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        if (SeedData.TryGetValue(trackingNumber, out var shipment))
        {
            return shipment;
        }

        throw new KeyNotFoundException($"Shipment with tracking number '{trackingNumber}' not found.");
    }
}

using System.Net.Http.Json;

namespace sv_cc43e56cc13a41819499ee7600f20493.Client.Services;

public sealed class HttpShipmentService(HttpClient httpClient) : IShipmentService
{
    public async Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var response = await httpClient.GetAsync($"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        if (response.StatusCode == System.Net.HttpStatusCode.NotFound)
        {
            throw new KeyNotFoundException($"Shipment with tracking number '{trackingNumber}' not found.");
        }

        response.EnsureSuccessStatusCode();

        return await response.Content.ReadFromJsonAsync<ShipmentDetails>(ct)
            ?? throw new InvalidOperationException("Received null shipment response.");
    }
}

using Microsoft.AspNetCore.Http.HttpResults;
using sv_cc43e56cc13a41819499ee7600f20493.Client.Services;

namespace sv_cc43e56cc13a41819499ee7600f20493;

public static class ShipmentApi
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        app.MapGet("api/shipments/{trackingNumber}", async Task<Results<Ok<ShipmentDetails>, NotFound>> (
            string trackingNumber,
            IShipmentService shipmentService,
            CancellationToken ct) =>
        {
            try
            {
                var shipment = await shipmentService.GetShipmentAsync(trackingNumber, ct);
                return TypedResults.Ok(shipment);
            }
            catch (KeyNotFoundException)
            {
                return TypedResults.NotFound();
            }
        });
    }
}

